const EdgeSidebar = React.forwardRef<HTMLDivElement, BoxProps>(
  function EdgeSidebar({ className, ...props }, ref) {
    return (
      // @ts-expect-error BoxProps on styled native element
      <StyledEdgeSidebarLeft
        ref={ref}
        {...props}
        className={`EdgeSidebar ${className || ""}`}
      />
